// ---------- Helpers ----------
function cleanNum(v){
  if (v == null || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'string'){
    var s = v.replace(/[%,$,\s]/g,'');
    var n = Number(s);
