function toRatio(v){
  if (typeof v === 'string' && v.includes('%')) return cleanNum(v)/100;
  var n = cleanNum(v);
  return n > 10 ? n/100 : n;
}

function sum(a,k){return a.reduce((s,x)=>s+cleanNum(x[k]||0),0)}
function mean(a,k){return a.length ? sum(a,k)/a.length : 0}

