// ---------- Helpers ----------
const cleanNum = (v) => {
  if (v == null || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'string') {
    // Strip $, %, commas, spaces
    const s = v.replace(/[%,$,\s]/g, '');
    const n = Number(s);
    return Number.isNaN(n) ? 0 : n;
  }
  const n = Number(v);
  return Number.isNaN(n) ? 0 : n;
};

const num = (v) => cleanNum(v);

/**
 * Ratio parser:
 * - "12%" -> 0.12
 * - 80    -> 0.80  (whole-number percent)
 * - 0.8   -> 0.8   (already ratio)
 * - 2.1   -> 2.1   (already ratio; do NOT /100 because your data uses >1 for 200%+)
 * Heuristic: divide by 100 only when numeric value > 10 (likely a whole-number percent)
 */
const ratio = (v) => {
  if (typeof v === 'string' && v.includes('%')) return cleanNum(v) / 100;
  const n = cleanNum(v);
  return n > 10 ? n / 100 : n;
};

const sumK = (arr, k) => arr.reduce((s, x) => s + num(x[k] || 0), 0);

const moneyShort = (n) => {
  const sign = n < 0 ? '-' : '';
  const a = Math.abs(num(n));
  if (a >= 1e9) return `${sign}$${(a / 1e9).toFixed(1)}B`;
  if (a >= 1e6) return `${sign}$${(a / 1e6).toFixed(1)}M`;
  if (a >= 1e3) return `${sign}$${(a / 1e3).toFixed(1)}K`;
  return `${sign}$${a.toFixed(2)}`;
};

const pct = (v) => `${(num(v) * 100).toFixed(1)}%`;

// ---------- Normalize inputs ----------
const hasOriginalShape = Array.isArray(data?.fields) && Array.isArray(data?.data);

const snapshot_time =
  (Array.isArray(data?.snapshot_time) ? data.snapshot_time[0] : data?.snapshot_time) ||
  data?.meta?.snapshot_time ||
  data?.snapshotTime ||
  null;

const raw =
  (Array.isArray(data?.raw_json) ? data.raw_json[0] : data?.raw_json) || {};

const rowsRaw =
  (hasOriginalShape && data.data) ||
  (Array.isArray(data) ? data : null) ||
  (Array.isArray(data?.rows) ? data.rows : null) ||
  (Array.isArray(raw?.data) ? raw.data : null) ||
  (Array.isArray(raw) ? raw : null) ||
  [];

// ---------- Field map / indices ----------
const fieldsArr =
  (hasOriginalShape && data.fields) ||
  (Array.isArray(raw?.fields) && raw.fields) ||
  [
    { name: 'Name' },
    { name: 'TechnicianBusinessUnit' },
    { name: 'CompletedRevenue' },
    { name: 'OpportunityJobAverage' },
    { name: 'TotalSales' },
    { name: 'SalesOpportunity' },
    { name: 'ClosedOpportunities' },
    { name: 'CloseRate' },
    { name: 'OpportunityAverageSale' },
    { name: 'ReplacementOpportunity' },
    { name: 'LeadsSet' },
    { name: 'ReplacementLeadConversionRate' },
    { name: 'TotalLeadSales' },
    { name: 'MembershipOpportunities' },
    { name: 'MembershipsSold' },
    { name: 'MembershipConversionRate' },
    { name: 'CompletedJobs' },
    { name: 'CallbackRate' },
    { name: 'PhotoUrl' },
  ];

const F = Object.fromEntries((fieldsArr || []).map((f, i) => [f.name, i]));
