  const installedRevenue = num(
    at(r, 'CompletedRevenue') ??
    at(r, 'Revenue') ??
    at(r, 'InstalledRevenue') ??
    at(r, 'TotalRevenue')
  );

  const jobsCompleted = num(
    at(r, 'CompletedJobs') ??
    at(r, 'ClosedOpportunities') ??
    at(r, 'JobsCompleted') ??
    at(r, 'Jobs')
  );

  const recallsCaused = num(at(r, 'RecallsCaused') ?? 0);

  const billableEfficiency = ratio(
    at(r, 'BillableEfficiency') ??
    at(r, 'CloseRate') ??
    at(r, 'ClosePct') ??
    at(r, 'ConversionRate')
  );

  const averageInstall = num(
    at(r, 'TotalJobAverage') ??
    at(r, 'OpportunityJobAverage') ??
    at(r, 'OpportunityAverageSale') ??
    at(r, 'AverageInstall') ??
    at(r, 'AvgTicket')
  );

  return {
    name,
    installedRevenue,
