    ? effNumer / totalJobsCompleted
    : (rows.length ? sumK(rows, 'billableEfficiency') / rows.length : 0);

const avgInstallNumer = rows.reduce(
  (s, x) => s + num(x.averageInstall) * num(x.jobsCompleted),
  0
);
const averageInstallAll =
  totalJobsCompleted > 0
    ? avgInstallNumer / totalJobsCompleted
    : (rows.length ? sumK(rows, 'averageInstall') / rows.length : 0);

