  billableEfficiencyAvg: Number(billableEfficiencyAvg.toFixed(3)), // 1.234 = 123.4%
  averageInstall: Number(averageInstallAll.toFixed(2)),

  // also include installedRevenue aggregate for convenience
  installedRevenue: totalInstalledRevenue,

  leaderName,
  leaderRevenue,
  leaderRevenueFormatted: moneyShort(leaderRevenue),
};

// ---------- Return ----------
return { rows, rows_ranked, totals, snapshot_time };
