// Output: { rows, rows_ranked, leader, snapshot_time }

function cleanNum(v){
  if (v == null || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  if (typeof v === 'string'){
    var n = Number(v.replace(/[%,$,\s]/g,''));
    return Number.isNaN(n) ? 0 : n;
  }
  var n = Number(v);
  return Number.isNaN(n) ? 0 : n;
}

function parseDeepString(s, maxDepth){
  var cur = s, depth = 0;
  while (depth < (maxDepth||5) && typeof cur === 'string'){
    var t = cur.trim()
      .replace(/&quot;/g, '"').replace(/&#34;/g, '"').replace(/&amp;/g, '&');
    if ((t.startsWith('"') && t.endsWith('"')) || (t.startsWith("'") && t.endsWith("'"))){
      t = t.slice(1, -1);
    }
    try { cur = JSON.parse(t); } catch(e){ break; }
    depth++;
  }
  return cur;
}

// snapshot_time
var snapshot_time =
  (Array.isArray(data?.snapshot_time) ? data.snapshot_time[0] : data?.snapshot_time) ||
  (Array.isArray(data?.meta?.snapshot_time) ? data.meta.snapshot_time[0] : data?.meta?.snapshot_time) ||
  null;

// Parse raw_json
var rawStr =
  (typeof data?.raw_json === 'string' && data.raw_json) ||
  (Array.isArray(data?.raw_json) && typeof data.raw_json[0] === 'string' && data.raw_json[0]) ||
  (typeof data?.data?.raw_json === 'string' && data.data.raw_json) ||
  (Array.isArray(data?.data?.raw_json) && typeof data.data.raw_json[0] === 'string' && data.data.raw_json[0]) ||
  null;

var obj = null;
if (rawStr) obj = parseDeepString(rawStr, 6);
if (!obj || typeof obj !== 'object'){
  obj = (Array.isArray(data?.fields) && Array.isArray(data?.data)) ? data : null;
}
if (!obj || !Array.isArray(obj.fields) || !Array.isArray(obj.data)){
  return { rows: [], rows_ranked: [], leader: null, snapshot_time };
}

// Build field index
var F = Object.fromEntries(obj.fields.map((f,i)=>[f.name,i]));
function at(row, key){
  if (!Array.isArray(row)) return row?.[key];
  var idx = F[key];
  return (typeof idx === 'number') ? row[idx] : undefined;
}

// Build rows with new mapping
var rows = obj.data.map(function(r){
  var leadsReceived     = cleanNum(at(r, 'LeadCalls'));
  var inboundBooked = cleanNum(at(r, 'InboundCallsBooked'));
  var manualBooked  = cleanNum(at(r, 'ManualCallsBooked'));
  var totalJobs     = inboundBooked + manualBooked;
  var cancelled     = cleanNum(at(r, 'CanceledBeforeDispatch'));
  var cancelRate    = totalJobs > 0 ? cancelled / totalJobs : 0;

  return {
    name: String(at(r, 'Name') ?? ''),
    leadsReceived,                     // целевые звонки
    inboundCallsBooked: inboundBooked, // работы из целевых звонков
    callBookingRate: cleanNum(at(r, 'InboundBookingRate')), // Call Booking Rate
    manualCallsBooked: manualBooked, // работы вручную
    totalJobsBooked: totalJobs,      // общее количество работ
    cancelledBeforeDispatch: cancelled, 
    cancellationRate: cancelRate
  };
}).filter(x =>
  x.name ||
  x.leadsReceived ||
  x.inboundCallsBooked ||
  x.manualCallsBooked ||
  x.totalJobsBooked ||
  x.cancelledBeforeDispatch
);

// Ranking by leadsReceived DESC, then totalJobs DESC, then name ASC
var rows_ranked = rows
  .slice()
  .sort((a,b)=>{
    if (b.leadsReceived !== a.leadsReceived) return b.leadsReceived - a.leadsReceived;
    if (b.totalJobsBooked !== a.totalJobsBooked) return b.totalJobsBooked - a.totalJobsBooked;
    return String(a.name).localeCompare(String(b.name));
  })
  .map((x,i)=>({ ...x, rankByLeadCalls: i+1 }));

var leader = rows_ranked[0] || null;

return { rows, rows_ranked, leader, snapshot_time };
