// How many booked leads     = goodLeads (your sample shows LeadsSet is the booked count)
// Booking rate (0..1)       = goodLeads / leadsGenerated (guard for /0)
const rows = rowsRaw.map(r => {
  const name = String(at(r,'Name') ?? '');

  const leadOpp      = num(at(r,'LeadGenerationOpportunity'));
  const leadsSet     = num(at(r,'LeadsSet'));
  const replOpp      = num(at(r,'ReplacementOpportunity'));
  const replLeadsSet = num(at(r,'ReplacementLeadsSet'));

  const leadsGenerated = leadOpp + replOpp;
  const goodLeads      = leadsSet + replLeadsSet;
  const bookedLeads    = goodLeads;
  const bookingRate    = leadsGenerated > 0 ? (goodLeads / leadsGenerated) : 0;

  return {
    name,
    leadsGenerated,
    goodLeads,
    bookedLeads,
    bookingRate
  };
}).filter(x => x.name);

