  else if (unit <= 3) niceUnit = 3;
  else if (unit <= 4) niceUnit = 4;
  else if (unit <= 5) niceUnit = 5;
  else niceUnit = 10;
  return niceUnit * pow10;
}


// Ensure at least 4 ticks have sensible spacing
const chartMax = niceCeil(candidateMax);

// Percent helper based on *chartMax* (NOT data max)
const pct = v => (Math.max(0, Math.min(1, (v || 0) / chartMax)) * 100).toFixed(2) + '%';

// Build bar HTML blocks (unchanged styles)
const monthBlocks = list
  .map(m => {
    const b24s = `
      <div class="bar y2024" data-tip="${fmtUSD(m.y2024.sales)}"   style="--h:${pct(m.y2024.sales)};  color:#8B4513">
        <span class="ink"></span>
      </div>`;
    const b24r = `
      <div class="bar y2024" data-tip="${fmtUSD(m.y2024.revenue)}" style="--h:${pct(m.y2024.revenue)};color:#4a90e2">
        <span class="ink"></span>
      </div>`;
    const b25s = `
      <div class="bar y2025" data-tip="${fmtUSD(m.y2025.sales)}"   style="--h:${pct(m.y2025.sales)};  color:#ff6b35">
        <span class="ink"></span>
      </div>`;
    const b25r = `
      <div class="bar y2025" data-tip="${fmtUSD(m.y2025.revenue)}" style="--h:${pct(m.y2025.revenue)};color:#20b2aa">
        <span class="ink"></span>
      </div>`;

    const goalTip = m.goal ? `Goal ${fmtUSD(m.goal)}${m.goalUpdatedAt ? ' • ' + new Date(m.goalUpdatedAt).toLocaleString() : ''}` : '';
    const goalLine = (m.goal > 0)
      ? `<div class="goal-line" data-tip="${goalTip}" style="--y:${pct(m.goal)};"></div>`
      : '';

    return `
      <div class="month">
        <div class="bars">
          ${b24s}${b24r}${b25s}${b25r}${goalLine}
        </div>
        <div class="x">${m.short}</div>
      </div>`;
  })
  .join('');

// ---------- Dynamic Y-Axis labels (5 lanes: top, 75%, 50%, 25%, 0) ----------
function fmtAxis(n){
  if (n >= 1_000_000) return `$${(n/1_000_000).toLocaleString('en-US', {maximumFractionDigits: n % 1_000_000 ? 1 : 0})}M`;
  if (n >= 1_000)     return `$${(n/1_000).toLocaleString('en-US', {maximumFractionDigits: 0})}k`;
  return `$${n}`;
}
const ticks = [1, 0.75, 0.5, 0.25, 0].map(t => Math.round(chartMax * t)); // rounded for clean labels
const labelsHtml = ticks.map(v => `<span>${fmtAxis(v)}</span>`).join('');

// Expose everything the page needs
return {
  html: monthBlocks,
  yLabels: labelsHtml,           // <— inject into the y-axis
  chartMax,                      // useful for debugging if you want to display it
  snapshot_time: trending?.snapshot_time || ''
};
