  .technician-cards-container {
  max-height: 82vh;
  overflow-y: auto;
  padding: 0;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/* === 4-column grid; Top1 spans two rows in column 1 ===
   Resulting placement by source order:
   Row1: [Top1][Top2][Top3][Top4]
   Row2: [Top1][Top5][Top6][Top7]
   Row3: [Top8][Top9][Top10][Top11] */
.cards-grid {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr)); /* 4 even columns */
  gap: 0.3vw;
  width: 100%;
  grid-auto-flow: row; /* keep natural order */
}

