.cards-grid > .tech-card:first-child {
  grid-column: 1;
  grid-row: 1 / span 3; /* shows in Row1 + Row2, Column 1 */
  position: relative;
  border: 0.104167vw solid transparent;
  background:
    linear-gradient(#ffffff, #ffffff) padding-box,
    linear-gradient(135deg, #FA6E18, #ffb26b) border-box;
  box-shadow: 0 0.3125vw 1.25vw rgba(250,110,24,0.25);
  transform: translateY(-0.052083vw);
  font-size: 1em;
}

.cards-grid > .tech-card:first-child {
  font-size: 1vw;
  font-weight: bold;
  line-height: 1vw;
}

.cards-grid > .tech-card:first-child .tech-image {
  width: 15vw; height: auto;
}

.cards-grid > .tech-card:first-child div.image-placeholder {
  width: 15vw; height: 15vw;
}

.cards-grid > .tech-card:first-child .card-content {
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.cards-grid > .tech-card:first-child .card-content p {
  font-size: 1.2vw;
  font-weight: bold;
  line-height: 1.2vw;
}

.cards-grid > .tech-card .card-content p {
  font-size: 1vw;
  font-weight: bold;
  line-height: 1vw;
}

.cards-grid > .tech-card:first-child .metric-label {
    font-size: 0.9vw;
  line-height: 0.9vw;
}

.cards-grid > .tech-card:first-child .metric-value {
    font-size: 0.9vw;
  line-height: 0.9vw;
}

/* Card base */
.tech-card {
  background: white;
  border-radius: 0.625vw;
  box-shadow: 0 0.104167vw 0.416667vw rgba(0,0,0,0.1);
  padding: 0.741667vw;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
  border: 0.052083vw solid #e9ecef;
  break-inside: avoid;
}

.tech-card:hover {
  transform: translateY(-0.104167vw);
  box-shadow: 0 0.208333vw 0.833333vw rgba(0,0,0,0.15);
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 0.833333vw;
  gap: 0.625vw;
}

.tech-info { flex: 1; min-width: 0; }

h3.tech-name {
  font-size: 1vw;
  line-height: 1vw;
  font-weight: 700;
  color: #1a1a1a;
  margin: 0 0 0.208333vw 0;
  word-wrap: break-word;
}

p.tech-bu {
  font-size: 0.8vw;
  line-height: 0.9vw; 
  color: #6c757d; 
  margin: 0; 
  font-weight: 500; 
}

.tech-rank {
  background: #FA6E18;
  color: white;
  padding: 0.260417vw;
  border-radius: 1.041667vw;
  font-weight: 700;
  font-size: 0.8vw;
  line-height: 0.9vw;
  min-width: 2.083333vw;
  text-align: center;
