}

.card-content { display: flex; gap: 0.833333vw; margin-bottom: 1.041667vw;align-items: center; }

.tech-image {
  width: 4vw; height: 4vw;
  border-radius: 0.416667vw; object-fit: cover;
  border: 0.104167vw solid #e9ecef; flex-shrink: 0;
}

div.image-placeholder {
  font-size: 0.8vw;
  line-height: 0.9vw;
  width: 4vw; height: 4vw; border-radius: 0.416667vw;
  background: #00363E; display: flex; align-items: center; justify-content: center;
  color: white; font-weight: 600; font-size: 1.5em;
  border: 0.104167vw solid #e9ecef; flex-shrink: 0;
}

.revenue-section { flex: 1; min-width: 0; align-items: center; }

p.revenue-label {
  font-size: 0.7vw;
  line-height: 0.8vw; 
  color: #000; 
  margin: 0 0 0.208333vw 0; 
  font-weight: 700; 
}

p.revenue-amount { 
  font-size: 0.7vw;
  line-height: 0.8vw;  
  font-weight: 700; 
  color: #1e7e34; 
  margin: 0;  
}

.metrics-grid { display: grid; grid-template-columns: 1fr; gap: 0.125vw; }

.metric-row {
  display: flex; justify-content: space-between; align-items: center;
  padding: 0.416667vw 0; border-bottom: 0.052083vw solid #f1f3f4;
}

.metric-row:last-child { border-bottom: none; }

span.metric-label { 
  font-size: 0.8vw;
  line-height: 0.5vw;  
  color: #000; 
  font-weight: 500; 
  flex: 1; 
